/**
 * cron-monitor.test.ts — withCronMonitor contract suite (ts-supabase-edge).
 *
 * Generated by the add-observability skill; lives in the project after
 * scaffold so future regenerations can detect breakage.
 *
 * Tests the Sentry Crons heartbeat wrapper contract from phase-22 CONTEXT.md:
 *   D1  — separate-wrapper export
 *   D5b — Composes as `withObservability(withCronMonitor(handler))` for the
 *         Supabase Edge stack (no `withSentry`, no `withObservabilityScheduled`;
 *         Sentry init is inline in the wrapper's existing `init()`).
 *   D6  — 3-source slug resolution (explicit > env > auto-derive)
 *         Supabase-edge auto-shape: `${SERVICE_NAME}:${handlerName ?? "scheduled"}`.
 *   D12 — schedule + maxRuntimeSeconds forwarded as Sentry monitorConfig (2nd
 *         arg) on the in_progress checkin only
 *   R04 (PLAN revisions) — SENTRY_DEBUG=1 opt-in console.error in catch blocks
 *
 * Two test seams are used:
 *   - `_setCaptureCheckInForTest`: substitutes the Sentry SDK boundary call.
 *     Mirrors the existing `_resetForTest` convention in this stack's
 *     `index.ts` — avoids monkey-patching the `npm:@sentry/deno` module
 *     under `deno test`, which has no `vi.mock` equivalent.
 *   - `Deno.env.set/delete`: per-test env mutation. Deno's global `Deno`
 *     namespace is read-only and cannot be reassigned, but its env API
 *     exposes `set`/`delete` — the idiomatic stub.
 *
 * Run with: deno test -A --no-check cron-monitor.test.ts
 */

import { assert, assertEquals, assertRejects } from "https://deno.land/std@0.224.0/assert/mod.ts";
import { withCronMonitor, _setCaptureCheckInForTest, _setWithMonitorForTest } from "./cron-monitor.ts";

// ─── Call-recorder for the Sentry SDK boundary ────────────────────────────────

interface CheckInCall {
  arg0: Record<string, unknown>;
  arg1: unknown;
}

interface Recorder {
  calls: CheckInCall[];
  returns: unknown[];
  impl: ((...args: unknown[]) => unknown) | null;
}

function makeRecorder(): Recorder {
  return { calls: [], returns: [], impl: null };
}

function bindRecorder(r: Recorder): void {
  _setCaptureCheckInForTest((arg0: Record<string, unknown>, arg1?: unknown) => {
    r.calls.push({ arg0, arg1 });
    if (r.impl) return r.impl(arg0, arg1);
    if (r.returns.length > 0) return r.returns.shift();
    return undefined;
  });
}

function resetRecorder(): void {
  _setCaptureCheckInForTest(null);
}

// ─── Env management ───────────────────────────────────────────────────────────
// Deno.env.set / delete is the only mutation surface — the `Deno` object
// itself is read-only. Tests track the keys they wrote so teardown can scrub
// them cleanly (no other test relies on these vars persisting).

const TEST_ENV_KEYS = [
  "SENTRY_DSN",
  "SENTRY_DEBUG",
  "SERVICE_NAME",
  "SENTRY_CRON_MONITOR_SLUG_SCHEDULED",
  "SENTRY_CRON_MONITOR_SLUG_INGEST_15MIN",
];

function installEnv(env: Record<string, string>): void {
  // Reset all known keys first, then apply.
  for (const k of TEST_ENV_KEYS) {
    try { Deno.env.delete(k); } catch { /* ignore */ }
  }
  for (const [k, v] of Object.entries(env)) {
    Deno.env.set(k, v);
  }
}

function restoreEnv(): void {
  for (const k of TEST_ENV_KEYS) {
    try { Deno.env.delete(k); } catch { /* ignore */ }
  }
}

// ─── §22.D1/D5b cron checkin behavior ─────────────────────────────────────────

Deno.test("withCronMonitor: emits in_progress + ok on happy path", async () => {
  const rec = makeRecorder();
  rec.returns.push("checkin-abc");
  bindRecorder(rec);
  installEnv({ SENTRY_DSN: "https://stub@sentry.io/1" });
  try {
    let called = 0;
    const handler = async (_req: Request): Promise<Response> => {
      called += 1;
      return new Response("ok");
    };
    const wrapped = withCronMonitor(handler, { monitorSlug: "callbot-sweep" });
    const res = await wrapped(new Request("https://stub/cron"));

    assertEquals(res.status, 200);
    assertEquals(called, 1);
    assertEquals(rec.calls.length, 2);
    assertEquals(rec.calls[0].arg0, { monitorSlug: "callbot-sweep", status: "in_progress" });
    assertEquals(rec.calls[1].arg0, { checkInId: "checkin-abc", monitorSlug: "callbot-sweep", status: "ok" });
  } finally {
    resetRecorder();
    restoreEnv();
  }
});

Deno.test("withCronMonitor: emits in_progress + error and re-throws on handler exception", async () => {
  const rec = makeRecorder();
  rec.returns.push("checkin-abc");
  bindRecorder(rec);
  installEnv({ SENTRY_DSN: "https://stub@sentry.io/1" });
  try {
    const boom = new Error("handler exploded");
    const handler = async (_req: Request): Promise<Response> => { throw boom; };
    const wrapped = withCronMonitor(handler, { monitorSlug: "callbot-sweep" });

    let caught: unknown;
    try {
      await wrapped(new Request("https://stub/cron"));
    } catch (e) {
      caught = e;
    }
    assertEquals(caught, boom);
    assertEquals(rec.calls.length, 2);
    assertEquals(rec.calls[0].arg0, { monitorSlug: "callbot-sweep", status: "in_progress" });
    assertEquals(rec.calls[1].arg0, { checkInId: "checkin-abc", monitorSlug: "callbot-sweep", status: "error" });
  } finally {
    resetRecorder();
    restoreEnv();
  }
});

