// ─── §22.D6 slug resolution ──────────────────────────────────────────────────

Deno.test("withCronMonitor: uses explicit config.monitorSlug above all sources", async () => {
  const rec = makeRecorder();
  rec.returns.push("checkin-abc");
  bindRecorder(rec);
  installEnv({
    SENTRY_DSN: "https://stub@sentry.io/1",
    SENTRY_CRON_MONITOR_SLUG_SCHEDULED: "env-loses",
    SERVICE_NAME: "auto-loses",
  });
  try {
    const handler = async (_req: Request): Promise<Response> => new Response("ok");
    const wrapped = withCronMonitor(handler, { monitorSlug: "explicit-wins" });
    await wrapped(new Request("https://stub/cron"));

    assert(rec.calls.length >= 1);
    assertEquals(rec.calls[0].arg0.monitorSlug, "explicit-wins");
  } finally {
    resetRecorder();
    restoreEnv();
  }
});

